import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface UserProfile {
  name: string;
  age: number;
  weight: number;
  dietaryPreference: string;
  allergies: string[];
  medicalConditions: string[];
  cookingLevel: 'Beginner' | 'Intermediate' | 'Pro';
  dailyCalories?: number;
}

export interface Ingredient {
  id: string;
  name: string;
  quantity: string;
  expiryDate: string;
  category: string;
}

export interface Recipe {
  id: string;
  title: string;
  description: string;
  calories: number;
  time: number;
  difficulty: string;
  ingredients: string[];
  steps: string[];
  whySuggested: string;
  indianContext?: string;
  healthWarnings?: string[];
}

export interface MealPlan {
  breakfast: Recipe;
  lunch: Recipe;
  dinner: Recipe;
  snacks: Recipe[];
}

export enum AppScreen {
  ONBOARDING = 'ONBOARDING',
  DASHBOARD = 'DASHBOARD',
  MEAL_PLANNER = 'MEAL_PLANNER',
  INVENTORY = 'INVENTORY',
  COOKING_ASSISTANT = 'COOKING_ASSISTANT',
  HEALTH_REPORT = 'HEALTH_REPORT',
  APPLIANCES = 'APPLIANCES'
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, Recipe, Ingredient } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getMealPlanSuggestions = async (
  profile: UserProfile, 
  availableIngredients: Ingredient[]
): Promise<Recipe[]> => {
  const prompt = `
    Suggest 3 healthy Indian-style recipes for a user with the following profile:
    - Age: ${profile.age}
    - Conditions: ${profile.medicalConditions.join(', ')}
    - Dietary Preference: ${profile.dietaryPreference}
    - Allergies: ${profile.allergies.join(', ')}
    - Available Ingredients: ${availableIngredients.map(i => i.name).join(', ')}

    Return the recipes in JSON format. For each recipe, include:
    - title
    - description
    - calories (number)
    - time (minutes)
    - difficulty
    - ingredients (list)
    - steps (list)
    - whySuggested (string explaining health benefits/conditions compatibility)
    - indianContext (how it fits Indian tastes)
    - healthWarnings (list of potential red flags like high salt if the user has BP)
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            calories: { type: Type.NUMBER },
            time: { type: Type.NUMBER },
            difficulty: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            steps: { type: Type.ARRAY, items: { type: Type.STRING } },
            whySuggested: { type: Type.STRING },
            indianContext: { type: Type.STRING },
            healthWarnings: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["title", "description", "calories", "time", "difficulty", "ingredients", "steps", "whySuggested"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
};

export const analyzeHealthReport = async (base64Data: string, mimeType: string) => {
  const prompt = `
    Analyze this medical report/image and extract:
    1. Key health parameters (glucose, cholesterol, BP if available).
    2. Dietary restrictions based on findings.
    3. Recommended daily calorie intake.

    Provide a supportive, non-alarmist summary.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          parameters: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: {
                name: { type: Type.STRING },
                value: { type: Type.STRING },
                status: { type: Type.STRING }
              } 
            }
          },
          recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestedDailyCalories: { type: Type.NUMBER },
          summary: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

import React from 'react';
import { AppScreen } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeScreen: AppScreen;
  setScreen: (screen: AppScreen) => void;
  title: string;
}

const Layout: React.FC<LayoutProps> = ({ children, activeScreen, setScreen, title }) => {
  const navItems = [
    { screen: AppScreen.DASHBOARD, icon: 'fa-house', label: 'Home' },
    { screen: AppScreen.MEAL_PLANNER, icon: 'fa-calendar-days', label: 'Meals' },
    { screen: AppScreen.INVENTORY, icon: 'fa-kitchen-set', label: 'Pantry' },
    { screen: AppScreen.HEALTH_REPORT, icon: 'fa-notes-medical', label: 'Health' },
    { screen: AppScreen.APPLIANCES, icon: 'fa-bolt', label: 'Smart' },
  ];

  if (activeScreen === AppScreen.ONBOARDING) return <>{children}</>;

  return (
    <div className="flex flex-col h-screen bg-gray-50 max-w-md mx-auto relative overflow-hidden shadow-2xl">
      {/* Header */}
      <header className="px-6 py-4 bg-white border-b border-gray-100 flex items-center justify-between sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">{title}</h1>
        <div className="w-8 h-8 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-700">
          <i className="fa-solid fa-user text-sm"></i>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-24 scroll-smooth">
        {children}
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-2 safe-area-bottom max-w-md mx-auto shadow-lg z-50">
        {navItems.map((item) => (
          <button
            key={item.screen}
            onClick={() => setScreen(item.screen)}
            className={`flex flex-col items-center justify-center px-4 py-2 transition-all ${
              activeScreen === item.screen ? 'text-emerald-600 scale-110' : 'text-gray-400'
            }`}
          >
            <i className={`fa-solid ${item.icon} text-lg mb-1`}></i>
            <span className="text-[10px] font-medium">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { UserProfile } from '../types';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState<UserProfile>({
    name: '',
    age: 25,
    weight: 70,
    dietaryPreference: 'Vegetarian',
    allergies: [],
    medicalConditions: [],
    cookingLevel: 'Beginner'
  });

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const dietaryOptions = ['Vegetarian', 'Vegan', 'Non-Vegetarian', 'Keto', 'Gluten-Free'];
  const conditions = ['Diabetes', 'Hypertension', 'High Cholesterol', 'PCOS', 'None'];

  return (
    <div className="h-full bg-white max-w-md mx-auto flex flex-col p-8">
      <div className="flex justify-between items-center mb-8">
        <div className="h-2 flex-1 bg-gray-100 rounded-full mr-4">
          <div className="h-full bg-emerald-500 rounded-full transition-all" style={{ width: `${(step / 3) * 100}%` }}></div>
        </div>
        <span className="text-sm font-bold text-emerald-600">{step}/3</span>
      </div>

      <div className="flex-1 space-y-8">
        {step === 1 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Welcome!</h2>
              <p className="text-gray-500 mt-2">Let's get to know you better for your personalized plan.</p>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">What's your name?</label>
                <input 
                  type="text" 
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                  placeholder="e.g. Rahul"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Age</label>
                  <input 
                    type="number" 
                    value={profile.age}
                    onChange={(e) => setProfile({...profile, age: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Weight (kg)</label>
                  <input 
                    type="number" 
                    value={profile.weight}
                    onChange={(e) => setProfile({...profile, weight: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Dietary Style</h2>
              <p className="text-gray-500 mt-2">Pick your lifestyle and preferences.</p>
            </div>

            <div className="space-y-3">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Primary Preference</label>
              {dietaryOptions.map(opt => (
                <button
                  key={opt}
                  onClick={() => setProfile({...profile, dietaryPreference: opt})}
                  className={`w-full text-left px-4 py-3 rounded-xl border transition-all ${
                    profile.dietaryPreference === opt 
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' 
                    : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Health Profile</h2>
              <p className="text-gray-500 mt-2">Select any conditions we should keep in mind.</p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              {conditions.map(c => (
                <button
                  key={c}
                  onClick={() => {
                    const exists = profile.medicalConditions.includes(c);
                    setProfile({
                      ...profile,
                      medicalConditions: exists 
                        ? profile.medicalConditions.filter(item => item !== c)
                        : [...profile.medicalConditions, c]
                    });
                  }}
                  className={`px-4 py-4 rounded-xl border text-center text-sm transition-all ${
                    profile.medicalConditions.includes(c)
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' 
                    : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-4">
        {step > 1 && (
          <button 
            onClick={prevStep}
            className="flex-1 py-4 text-gray-500 font-bold"
          >
            Back
          </button>
        )}
        <button 
          onClick={step === 3 ? () => onComplete(profile) : nextStep}
          disabled={step === 1 && !profile.name}
          className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-bold shadow-lg shadow-emerald-200 disabled:bg-gray-200"
        >
          {step === 3 ? 'Get Started' : 'Next'}
        </button>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState } from 'react';
import { Recipe } from '../types';

interface CookingAssistantProps {
  recipe: Recipe;
  onClose: () => void;
}

const CookingAssistant: React.FC<CookingAssistantProps> = ({ recipe, onClose }) => {
  const [currentStep, setCurrentStep] = useState(0);

  const nextStep = () => {
    if (currentStep < recipe.steps.length - 1) {
      setCurrentStep(currentStep + 1);
    }
  };

  const prevStep = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  return (
    <div className="fixed inset-0 bg-white z-[60] flex flex-col max-w-md mx-auto">
      <div className="px-6 py-4 bg-emerald-600 text-white flex items-center justify-between">
        <button onClick={onClose} className="p-2"><i className="fa-solid fa-xmark"></i></button>
        <h2 className="font-bold truncate px-4">{recipe.title}</h2>
        <button className="p-2"><i className="fa-solid fa-microphone"></i></button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {/* Step Visual Progress */}
        <div className="flex gap-1">
          {recipe.steps.map((_, idx) => (
            <div 
              key={idx} 
              className={`h-1 flex-1 rounded-full ${idx <= currentStep ? 'bg-emerald-500' : 'bg-gray-100'}`}
            ></div>
          ))}
        </div>

        {/* Health Warnings */}
        {recipe.healthWarnings && recipe.healthWarnings.length > 0 && (
          <div className="bg-amber-50 border border-amber-100 p-4 rounded-xl flex gap-3">
            <i className="fa-solid fa-triangle-exclamation text-amber-600"></i>
            <div>
              <p className="text-xs font-bold text-amber-800">Chef's Health Note</p>
              <p className="text-xs text-amber-700">{recipe.healthWarnings[0]}</p>
            </div>
          </div>
        )}

        {/* Current Instruction */}
        <div className="space-y-4">
          <span className="text-emerald-600 font-bold text-sm">Step {currentStep + 1} of {recipe.steps.length}</span>
          <h3 className="text-2xl font-bold text-gray-800 leading-tight">
            {recipe.steps[currentStep]}
          </h3>
          <div className="w-full aspect-video bg-gray-100 rounded-2xl flex items-center justify-center">
             <i className="fa-solid fa-play text-4xl text-emerald-500"></i>
          </div>
        </div>

        {/* Ingredients for this step (mock filter) */}
        <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
           <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Step Tip</p>
           <p className="text-sm text-gray-700">Make sure to stir continuously to prevent sticking, especially since we're using less oil as requested.</p>
        </div>
      </div>

      <div className="p-6 border-t border-gray-100 bg-white flex gap-4">
        <button 
          onClick={prevStep}
          disabled={currentStep === 0}
          className="flex-1 py-4 border border-gray-200 rounded-2xl text-gray-500 font-bold disabled:opacity-30"
        >
          Previous
        </button>
        <button 
          onClick={currentStep === recipe.steps.length - 1 ? onClose : nextStep}
          className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-bold shadow-lg"
        >
          {currentStep === recipe.steps.length - 1 ? 'Finish' : 'Next Step'}
        </button>
      </div>
    </div>
  );
};

export default CookingAssistant;

