    { id: '1', name: 'Spinach', quantity: '200g', expiryDate: '2023-11-20', category: 'Vegetables' },
    { id: '2', name: 'Paneer', quantity: '250g', expiryDate: '2023-11-22', category: 'Dairy' },
  ]);

