              <p className="text-gray-400 text-sm mt-1">Optimization: HealthSync™ mode enabled for 20% less oil absorption.</p>
              <div className="flex items-center gap-6 mt-6">
                <div>
                  <p className="text-gray-500 text-[10px] uppercase">Temp</p>
                  <p className="text-xl font-bold">180°C</p>
                </div>
                <div className="w-px h-8 bg-gray-800"></div>
