              <button className="mt-8 w-full py-4 bg-emerald-500 text-white rounded-2xl font-bold">Start Preheating</button>
             </div>
             <i className="fa-solid fa-wind absolute -right-4 -bottom-4 text-9xl text-white/5 rotate-12"></i>
           </div>

           <div className="grid grid-cols-2 gap-4">
             <div className="p-4 bg-white border border-gray-100 rounded-2xl flex flex-col justify-between">
               <i className="fa-solid fa-fire-burner text-gray-400"></i>
