        <h2 className="font-bold truncate px-4 text-sm uppercase tracking-wider">ChefAI Guide</h2>
        <button 
          onClick={() => playStep(currentStep)}
          className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-white text-emerald-600 animate-pulse' : 'bg-emerald-500 text-white'}`}
        >
          <i className="fa-solid fa-volume-high"></i>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        <div className="flex gap-1 mb-4">
          {recipe.steps.map((_, idx) => (
            <div 
              key={idx} 
              className={`h-1 flex-1 rounded-full transition-all duration-500 ${idx <= currentStep ? 'bg-emerald-500' : 'bg-gray-100'}`}
            ></div>
          ))}
        </div>

        {recipe.healthWarnings && recipe.healthWarnings.length > 0 && (
          <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex gap-3 animate-bounce-short">
            <i className="fa-solid fa-triangle-exclamation text-amber-600"></i>
            <div>
              <p className="text-[10px] font-bold text-amber-800 uppercase">Health Guard Alert</p>
              <p className="text-xs text-amber-700 font-medium">{recipe.healthWarnings[0]}</p>
            </div>
          </div>
        )}

        <div className="space-y-6">
          <div className="flex justify-between items-end">
            <span className="text-emerald-600 font-black text-xs uppercase">Step {currentStep + 1} of {recipe.steps.length}</span>
            <span className="text-[10px] font-bold text-gray-400">South Indian Heritage</span>
          </div>

          <h3 className="text-2xl font-bold text-gray-800 leading-snug">
            {recipe.steps[currentStep]}
          </h3>

          <div className="relative rounded-3xl overflow-hidden aspect-video bg-gray-100 flex items-center justify-center shadow-inner group">
             <i className="fa-solid fa-play text-5xl text-emerald-500/20 group-hover:text-emerald-500 transition-all"></i>
             <div className="absolute bottom-4 left-4 right-4 bg-black/40 backdrop-blur-md p-3 rounded-2xl flex justify-between items-center text-white">
                <p className="text-[10px] font-bold">Watch Video Guide</p>
                <i className="fa-solid fa-up-right-from-square text-[10px]"></i>
             </div>
          </div>
        </div>

        <div className="p-5 bg-emerald-50 rounded-3xl border border-emerald-100 relative overflow-hidden">
           <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-2">Smart Assist Tip</p>
           <p className="text-sm text-emerald-800 font-medium leading-relaxed relative z-10">
             {recipe.indianContext || "Add a pinch of curry leaves now to release the essential oils that help with digestion."}
           </p>
           <i className="fa-solid fa-seedling absolute -right-4 -bottom-4 text-6xl text-emerald-600/5 rotate-12"></i>
        </div>
      </div>

      <div className="p-6 border-t border-gray-100 bg-white flex gap-4 safe-area-bottom">
