    allergies: [] as string[],
    medicalConditions: [] as string[],
    cookingLevel: 'Beginner',
    subscription: 'Free'
  });

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const dietaryOptions = ['Vegetarian', 'Vegan', 'Non-Vegetarian', 'Keto', 'Gluten-Free'];
  const conditions = ['Diabetes', 'Hypertension', 'High Cholesterol', 'PCOS', 'None'];

  return (
    <div className="h-full bg-white max-w-md mx-auto flex flex-col p-8">
      <div className="flex justify-between items-center mb-8">
        <div className="h-2 flex-1 bg-gray-100 rounded-full mr-4">
          <div className="h-full bg-emerald-500 rounded-full transition-all" style={{ width: `${(step / 3) * 100}%` }}></div>
        </div>
        <span className="text-sm font-bold text-emerald-600">{step}/3</span>
      </div>

      <div className="flex-1 space-y-8">
        {step === 1 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Welcome!</h2>
              <p className="text-gray-500 mt-2">Let's get to know you better for your personalized plan.</p>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">What's your name?</label>
                <input 
                  type="text" 
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                  placeholder="e.g. Rahul"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Age</label>
                  <input 
                    type="number" 
                    value={profile.age}
                    onChange={(e) => setProfile({...profile, age: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Weight (kg)</label>
                  <input 
                    type="number" 
                    value={profile.weight}
                    onChange={(e) => setProfile({...profile, weight: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Dietary Style</h2>
              <p className="text-gray-500 mt-2">Pick your lifestyle and preferences.</p>
            </div>

            <div className="space-y-3">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Primary Preference</label>
              {dietaryOptions.map(opt => (
                <button
                  key={opt}
                  onClick={() => setProfile({...profile, dietaryPreference: opt})}
                  className={`w-full text-left px-4 py-3 rounded-xl border transition-all ${
                    profile.dietaryPreference === opt 
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' 
                    : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Health Profile</h2>
              <p className="text-gray-500 mt-2">Select any conditions we should keep in mind.</p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              {conditions.map(c => (
                <button
                  key={c}
                  onClick={() => {
                    const exists = profile.medicalConditions.includes(c);
                    setProfile({
                      ...profile,
                      medicalConditions: exists 
                        ? profile.medicalConditions.filter(item => item !== c)
                        : [...profile.medicalConditions, c]
