      <div className="mt-8 flex gap-4">
        {step > 1 && (
          <button 
            onClick={prevStep}
            className="flex-1 py-4 text-gray-500 font-bold"
          >
            Back
          </button>
        )}
        <button 
          onClick={step === 3 ? () => onComplete(profile) : nextStep}
          disabled={step === 1 && !profile.name}
          className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-bold shadow-lg shadow-emerald-200 disabled:bg-gray-200"
        >
          {step === 3 ? 'Get Started' : 'Next'}
        </button>
      </div>
    </div>
  );
};

export default Onboarding;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { UserProfile, Recipe, Ingredient } from "../types";

// Fixed: Using process.env.API_KEY directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMealPlanSuggestions = async (
  profile: UserProfile, 
  availableIngredients: Ingredient[]
): Promise<Recipe[]> => {
  const prompt = `
    Suggest 3 healthy South Indian recipes (e.g., variants of Dosa, Idli, Sambar, Rasam, Avial) for a user:
    - Age: ${profile.age}
    - Conditions: ${profile.medicalConditions.join(', ')}
    - Dietary Preference: ${profile.dietaryPreference}
    - Allergies: ${profile.allergies.join(', ')}
    - Available Pantry: ${availableIngredients.map(i => i.name).join(', ')}

    Return the recipes in JSON format. For each recipe, include:
    - title, description, calories (number), time (minutes), difficulty, ingredients (list), steps (list), whySuggested, indianContext, healthWarnings (list).
    IMPORTANT: Focus on South Indian flavours and ingredients.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            calories: { type: Type.NUMBER },
            time: { type: Type.NUMBER },
            difficulty: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            steps: { type: Type.ARRAY, items: { type: Type.STRING } },
            whySuggested: { type: Type.STRING },
            indianContext: { type: Type.STRING },
            healthWarnings: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["title", "description", "calories", "time", "difficulty", "ingredients", "steps", "whySuggested"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
};

export const getMotivationalMessage = async (history: {role: string, text: string}[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
    config: {
      systemInstruction: "You are SmartChef Assistant. You provide motivational support, mental wellness tips, and culinary inspiration. Be warm, empathetic, and encouraging. Focus on healthy habits and South Indian heritage when relevant."
    }
  });
  return response.text;
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Read this instruction clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    console.error("TTS Error", e);
    return undefined;
  }
};

