            type="number"
            value={age}
            onChange={(e) => setAge(e.target.value)}
            placeholder="Age"
            className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl text-sm outline-none focus:ring-2 focus:ring-emerald-500"
