import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Onboarding from './screens/Onboarding';
import Dashboard from './screens/Dashboard';
import CookingAssistant from './screens/CookingAssistant';
import Inventory from './screens/Inventory';
import HealthReport from './screens/HealthReport';
import MotivationChat from './screens/MotivationChat';
import Subscription from './screens/Subscription';
import MealPlanner from './screens/MealPlanner';
import FamilyManagement from './screens/FamilyManagement';
import { AppScreen, UserProfile, Recipe, Ingredient, FamilyMember } from './types';
import { getMealPlanSuggestions } from './services/gemini';

const App: React.FC = () => {
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.ONBOARDING);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [suggestions, setSuggestions] = useState<Recipe[]>([]);
  const [selectedRecipe, setSelectedRecipe] = useState<Recipe | null>(null);
  const [inventory, setInventory] = useState<Ingredient[]>([
    { id: '1', name: 'Curry Leaves', quantity: '50g', expiryDate: new Date(Date.now() + 86400000 * 1).toISOString(), category: 'Herbs' },
    { id: '2', name: 'Desiccated Coconut', quantity: '200g', expiryDate: new Date(Date.now() + 86400000 * 15).toISOString(), category: 'Staples' },
    { id: '3', name: 'Mustard Seeds', quantity: '100g', expiryDate: new Date(Date.now() + 86400000 * 60).toISOString(), category: 'Spices' },
  ]);

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    setProfile({ ...newProfile, subscription: 'Free', familyMembers: [] });
    setActiveScreen(AppScreen.DASHBOARD);
  };

  const handleScan = () => {
    const newItems: Ingredient[] = [
      { id: Date.now().toString(), name: 'Idli Batter', quantity: '1kg', expiryDate: new Date(Date.now() + 86400000 * 3).toISOString(), category: 'Batter' },
      { id: (Date.now() + 1).toString(), name: 'Sambar Onions', quantity: '250g', expiryDate: new Date(Date.now() + 86400000 * 7).toISOString(), category: 'Vegetables' },
      { id: (Date.now() + 2).toString(), name: 'Ghee', quantity: '500ml', expiryDate: new Date(Date.now() + 86400000 * 180).toISOString(), category: 'Fats' },
    ];
    setInventory(prev => [...prev, ...newItems]);
  };

  const addFamilyMember = (member: FamilyMember) => {
    if (profile) {
      setProfile({ ...profile, familyMembers: [...profile.familyMembers, member] });
    }
  };

  const removeFamilyMember = (id: string) => {
    if (profile) {
      setProfile({ ...profile, familyMembers: profile.familyMembers.filter(m => m.id !== id) });
    }
  };

  useEffect(() => {
    if (profile && activeScreen === AppScreen.DASHBOARD) {
      const fetchSuggestions = async () => {
        try {
          const recipes = await getMealPlanSuggestions(profile, inventory);
          setSuggestions(recipes);
        } catch (error) {
          console.error("Failed to fetch suggestions", error);
        }
      };
      fetchSuggestions();
    }
  }, [profile, activeScreen, inventory]);

  const getTitle = () => {
    switch(activeScreen) {
      case AppScreen.DASHBOARD: return 'SmartChef';
      case AppScreen.MEAL_PLANNER: return 'Family Meals';
      case AppScreen.INVENTORY: return 'Smart Pantry';
      case AppScreen.HEALTH_REPORT: return 'Health Analytics';
      case AppScreen.APPLIANCES: return 'Smart Kitchen';
      case AppScreen.MOTIVATION_CHAT: return 'Assistant Chat';
      case AppScreen.SUBSCRIPTION: return 'SmartChef Upgrade';
      case AppScreen.FAMILY_MANAGEMENT: return 'Family Profiles';
      default: return 'SmartChef';
    }
  };

  return (
    <Layout 
      activeScreen={activeScreen} 
      setScreen={setActiveScreen} 
      title={getTitle()}
    >
      {activeScreen === AppScreen.ONBOARDING && (
        <Onboarding onComplete={handleOnboardingComplete} />
      )}

      {activeScreen === AppScreen.DASHBOARD && profile && (
        <>
          <Dashboard 
            profile={profile} 
            suggestions={suggestions} 
            onSelectRecipe={(r) => setSelectedRecipe(r)}
            setScreen={setActiveScreen}
          />
          <div className="px-6 pb-6">
             <button 
              onClick={() => setActiveScreen(AppScreen.MOTIVATION_CHAT)}
              className="w-full bg-emerald-100 text-emerald-700 py-4 rounded-[2rem] font-bold flex items-center justify-center gap-3 border border-emerald-200 active:scale-95 transition-all shadow-sm"
             >
               <i className="fa-solid fa-comment-dots text-lg"></i>
               Multilingual AI Assistant
             </button>
          </div>
        </>
      )}

      {activeScreen === AppScreen.INVENTORY && (
        <Inventory items={inventory} onAdd={() => {}} onScan={handleScan} />
      )}

      {activeScreen === AppScreen.MEAL_PLANNER && (
        <MealPlanner />
      )}

      {activeScreen === AppScreen.HEALTH_REPORT && (
        <HealthReport />
      )}

      {activeScreen === AppScreen.MOTIVATION_CHAT && (
        <MotivationChat />
      )}

      {activeScreen === AppScreen.SUBSCRIPTION && profile && (
        <Subscription profile={profile} onUpdate={(tier) => setProfile({...profile, subscription: tier})} />
      )}

      {activeScreen === AppScreen.FAMILY_MANAGEMENT && profile && (
        <FamilyManagement 
          profile={profile} 
          onAddMember={addFamilyMember} 
          onRemoveMember={removeFamilyMember}
          onClose={() => setActiveScreen(AppScreen.DASHBOARD)}
        />
      )}

      {activeScreen === AppScreen.APPLIANCES && (
        <div className="p-6 space-y-6 pb-24">
           <div className="bg-gray-900 p-8 rounded-[2.5rem] text-white space-y-4 overflow-hidden relative shadow-2xl">
             <div className="relative z-10">
              <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest mb-1">Active Device • Preheating</p>
              <h3 className="text-2xl font-black">Smart Air Fryer</h3>
              <p className="text-gray-400 text-sm mt-2 font-medium">Optimization: HealthSync™ mode enabled for low-oil Samosas.</p>
              <div className="flex items-center gap-8 mt-6">
                <div className="flex flex-col">
                  <span className="text-gray-500 text-[8px] uppercase font-black tracking-widest mb-1">Temp</span>
                  <span className="text-2xl font-black tracking-tighter">180°C</span>
                </div>
                <div className="w-px h-8 bg-gray-800"></div>
                <div className="flex flex-col">
                  <span className="text-gray-500 text-[8px] uppercase font-black tracking-widest mb-1">Time</span>
                  <span className="text-2xl font-black tracking-tighter">12:00</span>
                </div>
              </div>
             </div>
             <i className="fa-solid fa-fire-burner absolute -right-6 -bottom-6 text-9xl text-white/5 -rotate-12"></i>
           </div>

           <h4 className="font-bold text-gray-800 px-1 uppercase text-xs tracking-widest">Connected Home</h4>
           <div className="grid grid-cols-2 gap-4">
             {[
               { name: 'Smart Fridge', status: 'Stable • 3°C', icon: 'fa-snowflake', color: 'text-blue-500', bg: 'bg-blue-50' },
               { name: 'TrashCan Pro', status: '60% Full', icon: 'fa-trash-can', color: 'text-amber-500', bg: 'bg-amber-50' },
               { name: 'Induction', status: 'Idle', icon: 'fa-fire-burner', color: 'text-gray-400', bg: 'bg-gray-50' },
               { name: 'Water Filter', status: 'Optimal', icon: 'fa-droplet', color: 'text-blue-400', bg: 'bg-blue-50' },
             ].map((device, i) => (
               <div key={i} className={`p-5 ${device.bg} rounded-[2rem] flex flex-col justify-between shadow-sm active:scale-95 transition-all cursor-pointer group`}>
                 <i className={`fa-solid ${device.icon} ${device.color} text-xl group-hover:scale-110 transition-transform`}></i>
                 <div className="mt-4">
                   <p className="font-bold text-xs text-gray-800">{device.name}</p>
                   <p className={`text-[10px] font-black uppercase ${device.color}`}>{device.status}</p>
                 </div>
               </div>
             ))}
           </div>
        </div>
      )}

      {selectedRecipe && (
        <CookingAssistant 
          recipe={selectedRecipe} 
          onClose={() => setSelectedRecipe(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

