import React, { useState } from 'react';
import { Ingredient } from '../types';

interface InventoryProps {
  items: Ingredient[];
  onAdd: (item: Ingredient) => void;
  onScan: () => void;
}

const Inventory: React.FC<InventoryProps> = ({ items, onAdd, onScan }) => {
  const [isScanning, setIsScanning] = useState(false);

  const getExpiryColor = (dateStr: string) => {
    const expiry = new Date(dateStr);
    const today = new Date();
    const diffDays = Math.ceil((expiry.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    if (diffDays <= 2) return 'border-red-500 bg-red-50 text-red-700';
    if (diffDays <= 5) return 'border-amber-500 bg-amber-50 text-amber-700';
    return 'border-emerald-500 bg-emerald-50 text-emerald-700';
  };

  const handleScanSim = () => {
    setIsScanning(true);
    setTimeout(() => {
      setIsScanning(false);
      onScan(); 
    }, 2000);
  };

  return (
    <div className="space-y-8 max-w-screen-xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h3 className="text-2xl font-black text-gray-800 tracking-tight">Smart Pantry</h3>
          <p className="text-gray-500 text-sm">Real-time inventory optimization powered by AI.</p>
        </div>
        <button 
          onClick={handleScanSim}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all hover:bg-emerald-700 font-bold"
        >
          <i className="fa-solid fa-camera text-lg"></i>
          <span>Scan Kitchen via AR</span>
        </button>
      </div>

      {isScanning && (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-sm flex flex-col items-center justify-center p-8">
          <div className="w-full max-w-lg aspect-square border-2 border-emerald-500 rounded-3xl relative overflow-hidden">
            <div className="absolute inset-x-0 top-0 h-1 bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,1)] animate-[bounce_2s_infinite]"></div>
            <div className="absolute inset-0 flex items-center justify-center">
              <i className="fa-solid fa-expand text-6xl text-white/10"></i>
            </div>
            <div className="absolute bottom-10 left-0 right-0 text-center">
              <p className="text-emerald-400 font-bold text-sm tracking-widest uppercase animate-pulse">Detecting Ingredients...</p>
            </div>
          </div>
          <p className="text-white mt-8 font-black text-2xl animate-pulse">ChefAI is scanning your fridge...</p>
        </div>
      )}

      {/* Grid for Pantry Items */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {items.length === 0 ? (
          <div className="col-span-full text-center py-32 text-gray-400 bg-white rounded-[2rem] border border-dashed border-gray-200">
            <i className="fa-solid fa-box-open text-6xl mb-6 text-gray-200"></i>
            <p className="text-lg font-bold">Your pantry is empty.</p>
            <p className="text-sm">Scan your kitchen to automatically detect items.</p>
          </div>
        ) : (
          items.map(item => {
            const daysLeft = Math.ceil((new Date(item.expiryDate).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
            return (
              <div 
                key={item.id} 
                className={`p-5 rounded-2xl border-l-4 shadow-sm bg-white flex items-center justify-between transition-all hover:scale-[1.02] hover:shadow-md cursor-pointer ${getExpiryColor(item.expiryDate).split(' ')[0]}`}
              >
                <div className="min-w-0">
                  <h4 className="font-bold text-gray-800 truncate">{item.name}</h4>
                  <p className="text-xs text-gray-500 truncate">{item.quantity} • {item.category}</p>
                </div>
                <div className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider flex-shrink-0 ${getExpiryColor(item.expiryDate).split(' ').slice(1).join(' ')}`}>
                  {daysLeft <= 0 ? 'Expired' : `${daysLeft} days`}
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Pro Optimization Card - Responsive */}
      <div className="bg-emerald-900 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group hover:scale-[1.01] transition-transform">
        <div className="flex flex-col md:flex-row gap-6 items-center md:items-start relative z-10">
          <div className="bg-emerald-500/20 p-4 rounded-3xl text-emerald-400 text-2xl group-hover:bg-emerald-500 group-hover:text-white transition-all">
            <i className="fa-solid fa-wand-magic-sparkles"></i>
          </div>
          <div className="text-center md:text-left">
            <h4 className="font-black text-xl md:text-2xl mb-2">Smart Pantry Optimization</h4>
            <p className="text-sm text-gray-300 leading-relaxed max-w-2xl">
              Based on your available Curry Leaves, Coconut, and Rice, I've prioritized South Indian breakfast recipes to minimize waste. 
              Optimization level: <span className="text-emerald-400 font-bold">Excellent (94%)</span>.
            </p>
          </div>
        </div>
        <i className="fa-solid fa-bolt absolute -right-8 -bottom-8 text-[12rem] text-white/5 rotate-12"></i>
      </div>
    </div>
  );
};

