import { GoogleGenAI, Type, Modality } from "@google/genai";
import { UserProfile, Recipe, Ingredient } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMealPlanSuggestions = async (
  profile: UserProfile, 
  availableIngredients: Ingredient[]
): Promise<Recipe[]> => {
  // Sort ingredients by expiry to mention in prompt
  const criticalIngredients = [...availableIngredients]
    .sort((a, b) => new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime())
    .slice(0, 5)
    .map(i => i.name)
    .join(', ');

  const familyContext = profile.familyMembers.length > 0 
    ? `Planning for a household with diverse needs: ${profile.familyMembers.map(m => `${m.name} (${m.dietaryPreference})`).join(', ')}.` 
    : '';

  const prompt = `
    Suggest 3 healthy South Indian recipes.
    - User: ${profile.name}, Age: ${profile.age}, Preference: ${profile.dietaryPreference}
    - Critical ingredients to use (nearing expiry): ${criticalIngredients}
    - ${familyContext}

    STRICT RULES:
    1. Only suggest recipes that can be certified by FSSAI/Apollo Health partners.
    2. Focus on South Indian flavours.
    3. Output must be valid JSON.
    4. Set "isCertified" to true only if the ingredients are standard health-approved staples.

    Return the recipes in JSON format:
    - title, description, calories (number), time (minutes), difficulty, ingredients (list), steps (list), whySuggested, indianContext, healthWarnings (list), isCertified (boolean).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              calories: { type: Type.NUMBER },
              time: { type: Type.NUMBER },
              difficulty: { type: Type.STRING },
              ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
              steps: { type: Type.ARRAY, items: { type: Type.STRING } },
              whySuggested: { type: Type.STRING },
              indianContext: { type: Type.STRING },
              healthWarnings: { type: Type.ARRAY, items: { type: Type.STRING } },
              isCertified: { type: Type.BOOLEAN }
            },
            required: ["title", "description", "calories", "time", "difficulty", "ingredients", "steps", "whySuggested", "isCertified"]
          }
        }
      }
    });

    const results = JSON.parse(response.text || '[]');
    // Only return certified recipes per user request
    return results.filter((r: Recipe) => r.isCertified === true);
  } catch (e) {
    console.error("Gemini Error", e);
    return [];
  }
};

export const getMotivationalMessage = async (history: {role: string, text: string}[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
    config: {
      systemInstruction: "You are SmartChef Assistant. You are a helpful guide, not a chatbot. Provide motivational support in multiple Indian languages. Focus on culinary health. Use a supportive, friendly, and guiding tone."
    }
  });
  return response.text;
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return undefined;
  }
};

