  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.LOGIN);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [suggestions, setSuggestions] = useState<Recipe[]>([]);
  const [selectedRecipe, setSelectedRecipe] = useState<Recipe | null>(null);
  const [inventory, setInventory] = useState<Ingredient[]>([
    { id: '1', name: 'Curry Leaves', quantity: '50g', expiryDate: new Date(Date.now() + 86400000 * 1).toISOString(), category: 'Herbs', isCertified: true },
    { id: '2', name: 'Coconut', quantity: '200g', expiryDate: new Date(Date.now() + 86400000 * 15).toISOString(), category: 'Staples', isCertified: true },
    { id: '3', name: 'Ghee', quantity: '100g', expiryDate: new Date(Date.now() + 86400000 * 60).toISOString(), category: 'Fats', isCertified: true },
  ]);

  // Restore data on load
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.isLoggedIn) {
          setProfile(parsed);
          setActiveScreen(AppScreen.WELCOME);
        }
      } catch (e) {
        console.error("Storage Restore Failed", e);
      }
    }
  }, []);

  // Persist data when profile changes
  useEffect(() => {
    if (profile) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
    }
  }, [profile]);

  const handleLogin = (method: 'Google' | 'Phone') => {
    // If returning user, restore would have handled it. 
    // This flow is for new or fresh logins.
    setActiveScreen(AppScreen.ONBOARDING);
  };

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    const finalProfile = { ...newProfile, isLoggedIn: true, subscription: 'Free' as const };
    setProfile(finalProfile);
    setActiveScreen(AppScreen.WELCOME);
  };

  const handleScan = () => {
    const newItems: Ingredient[] = [
      { id: Date.now().toString(), name: 'Idli Batter', quantity: '1kg', expiryDate: new Date(Date.now() + 86400000 * 3).toISOString(), category: 'Batter', isCertified: true },
      { id: (Date.now() + 1).toString(), name: 'Sambar Onions', quantity: '250g', expiryDate: new Date(Date.now() + 86400000 * 7).toISOString(), category: 'Vegetables', isCertified: true },
    ];
    setInventory(prev => [...prev, ...newItems]);
  };

  useEffect(() => {
    if (profile && activeScreen === AppScreen.DASHBOARD) {
      const fetchSuggestions = async () => {
        try {
          const recipes = await getMealPlanSuggestions(profile, inventory);
          setSuggestions(recipes);
        } catch (error) {
          console.error("Failed to fetch suggestions", error);
        }
      };
      fetchSuggestions();
    }
  }, [profile, activeScreen, inventory]);

  const getTitle = () => {
    switch(activeScreen) {
      case AppScreen.DASHBOARD: return 'SmartChef';
      case AppScreen.MEAL_PLANNER: return 'Family Meals';
      case AppScreen.INVENTORY: return 'Smart Pantry';
      case AppScreen.HEALTH_REPORT: return 'Health Analytics';
      case AppScreen.APPLIANCES: return 'Smart Kitchen';
      case AppScreen.MOTIVATION_CHAT: return 'Assistant Chat';
      case AppScreen.SUBSCRIPTION: return 'Chef Upgrade';
      case AppScreen.FAMILY_MANAGEMENT: return 'Family Hub';
      case AppScreen.PROFILE_EDIT: return 'Edit Profile';
      default: return 'SmartChef';
    }
  };

  if (activeScreen === AppScreen.LOGIN) return <Login onLogin={handleLogin} />;
  if (activeScreen === AppScreen.WELCOME) return <Welcome onContinue={() => setActiveScreen(AppScreen.DASHBOARD)} userName={profile?.name} />;

  return (
    <Layout 
      activeScreen={activeScreen} 
      setScreen={setActiveScreen} 
      title={getTitle()}
    >
      {activeScreen === AppScreen.ONBOARDING && (
        <Onboarding onComplete={handleOnboardingComplete} />
      )}

      {activeScreen === AppScreen.DASHBOARD && profile && (
        <>
          <Dashboard 
            profile={profile} 
            suggestions={suggestions} 
            onSelectRecipe={(r) => setSelectedRecipe(r)}
            setScreen={setActiveScreen}
          />
          <div className="px-6 pb-6 max-w-screen-xl mx-auto">
             <button 
              onClick={() => setActiveScreen(AppScreen.MOTIVATION_CHAT)}
              className="w-full bg-emerald-100 text-emerald-700 py-4 rounded-[2rem] font-black flex items-center justify-center gap-3 border border-emerald-200 active:scale-95 transition-all shadow-sm uppercase tracking-widest text-xs"
             >
               <i className="fa-solid fa-comment-dots text-lg"></i>
               Talk to Chef Assistant
             </button>
          </div>
        </>
      )}

      {activeScreen === AppScreen.INVENTORY && (
        <Inventory items={inventory} onAdd={() => {}} onScan={handleScan} />
      )}

      {activeScreen === AppScreen.MEAL_PLANNER && (
        <MealPlanner />
      )}

      {activeScreen === AppScreen.HEALTH_REPORT && (
        <HealthReport />
      )}

      {activeScreen === AppScreen.MOTIVATION_CHAT && (
        <MotivationChat />
      )}

      {activeScreen === AppScreen.SUBSCRIPTION && profile && (
        <Subscription profile={profile} onUpdate={(tier) => setProfile({...profile, subscription: tier})} />
      )}

      {activeScreen === AppScreen.FAMILY_MANAGEMENT && profile && (
        <FamilyManagement 
          profile={profile} 
          onAddMember={(m) => setProfile({...profile, familyMembers: [...profile.familyMembers, m]})} 
          onRemoveMember={(id) => setProfile({...profile, familyMembers: profile.familyMembers.filter(f => f.id !== id)})}
          onClose={() => setActiveScreen(AppScreen.DASHBOARD)}
        />
      )}

      {activeScreen === AppScreen.PROFILE_EDIT && profile && (
        <ProfileEdit 
          profile={profile}
          onSave={(updated) => { setProfile(updated); setActiveScreen(AppScreen.DASHBOARD); }}
          onClose={() => setActiveScreen(AppScreen.DASHBOARD)}
        />
      )}

      {activeScreen === AppScreen.APPLIANCES && (
        <div className="p-6 space-y-6 pb-24 max-w-screen-xl mx-auto">
           <div className="bg-gray-900 p-8 rounded-[2.5rem] text-white space-y-4 overflow-hidden relative shadow-2xl">
             <div className="relative z-10">
              <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest mb-1">Active • Syncing</p>
              <h3 className="text-2xl font-black">Smart Air Fryer</h3>
              <p className="text-gray-400 text-sm mt-2">Optimization: HealthSync™ mode enabled for low-oil Samosas.</p>
              <div className="flex items-center gap-8 mt-6">
                <div className="flex flex-col">
                  <span className="text-gray-500 text-[8px] uppercase font-black tracking-widest">Temp</span>
                  <span className="text-2xl font-black">180°C</span>
                </div>
                <div className="w-px h-8 bg-gray-800"></div>
                <div className="flex flex-col">
                  <span className="text-gray-500 text-[8px] uppercase font-black tracking-widest">Time</span>
                  <span className="text-2xl font-black">12:00</span>
                </div>
              </div>
             </div>
             <i className="fa-solid fa-fire-burner absolute -right-6 -bottom-6 text-9xl text-white/5 -rotate-12"></i>
           </div>

           <div className="grid grid-cols-2 gap-4">
             {[
               { name: 'Smart Fridge', status: 'Stable', icon: 'fa-snowflake', color: 'text-blue-500' },
               { name: 'TrashCan Pro', status: '60% Full', icon: 'fa-trash-can', color: 'text-amber-500' },
             ].map((device, i) => (
               <div key={i} className="p-5 bg-white border border-gray-100 rounded-[2rem] flex flex-col justify-between shadow-sm">
                 <i className={`fa-solid ${device.icon} ${device.color} text-xl`}></i>
                 <div className="mt-4">
                   <p className="font-bold text-xs text-gray-800">{device.name}</p>
                   <p className={`text-[10px] font-black uppercase ${device.color}`}>{device.status}</p>
                 </div>
               </div>
             ))}
           </div>
        </div>
      )}

      {selectedRecipe && (
        <CookingAssistant 
          recipe={selectedRecipe} 
          onClose={() => setSelectedRecipe(null)} 
        />
      )}
    </Layout>
  );
};

