      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 md:p-12 rounded-[3rem] border border-gray-100 shadow-sm space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-12">
            {[
              { type: 'breakfast', icon: 'fa-mug-hot', color: 'bg-amber-50 text-amber-600' },
              { type: 'lunch', icon: 'fa-bowl-rice', color: 'bg-emerald-50 text-emerald-600' },
