                <div className="flex-1">
                  <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-1">{m.type}</p>
                  <h4 className="font-bold text-gray-800 leading-tight">{(currentPlan as any)?.[m.type]}</h4>
