                key={idx} 
                onClick={() => onSelectRecipe(recipe)}
                className="group active:scale-95 transition-all cursor-pointer bg-white border border-gray-100 p-6 rounded-[2.5rem] shadow-sm flex flex-col gap-4 hover:shadow-2xl hover:border-emerald-300 relative overflow-hidden"
              >
                <div className="flex gap-5 items-center">
                  <div className="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center shrink-0">
                    <i className="fa-solid fa-utensils text-emerald-600 text-2xl"></i>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-bold text-gray-800 text-lg leading-tight truncate">{recipe.title}</h4>
                    <div className="flex items-center gap-2 mt-1">
                      <span className={`w-2 h-2 rounded-full ${isAvailable ? 'bg-emerald-500' : 'bg-red-400'}`}></span>
                      <span className="text-[9px] font-black uppercase text-gray-400">
                        {isAvailable ? 'All Ingredients Available' : 'Missing Ingredients'}
                      </span>
                    </div>
                  </div>
                </div>
                <div className="flex items-center justify-between mt-2 pt-4 border-t border-gray-50">
                   <div className="flex gap-4">
                     <span className="text-[10px] font-black text-gray-600 uppercase">{recipe.calories} kcal</span>
