import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Login from './screens/Login';
import Welcome from './screens/Welcome';
import Onboarding from './screens/Onboarding';
import Dashboard from './screens/Dashboard';
import CookingAssistant from './screens/CookingAssistant';
import Inventory from './screens/Inventory';
import HealthReport from './screens/HealthReport';
import MotivationChat from './screens/MotivationChat';
import Subscription from './screens/Subscription';
import MealPlanner from './screens/MealPlanner';
import FamilyManagement from './screens/FamilyManagement';
import ProfileEdit from './screens/ProfileEdit';
import History from './screens/History';
import Partner from './screens/Partner';
import { AppScreen, UserProfile, Recipe, Ingredient, ConsumptionLog } from './types';
import { getMealPlanSuggestions } from './services/gemini';

const STORAGE_KEY = 'smart_chef_user_data';

const milestonePuns = [
  "Milestone reached! Your body is basically a temple now, albeit one that really likes dosa.",
  "Achievement unlocked: Professional Hydrator. The ocean is calling for tips.",
  "Health goal met! Your metabolism just did a happy dance.",
  "You're crushing it! If health was a sport, you'd be in the hall of fame.",
];

const App: React.FC = () => {
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.LOGIN);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [suggestions, setSuggestions] = useState<Recipe[]>([]);
  const [selectedRecipe, setSelectedRecipe] = useState<Recipe | null>(null);
  const [history, setHistory] = useState<ConsumptionLog[]>([]);
  const [inventory, setInventory] = useState<Ingredient[]>([
    { id: '1', name: 'Curry Leaves', quantity: '50g', expiryDate: new Date(Date.now() + 86400000 * 1).toISOString(), category: 'Herbs', isCertified: true },
    { id: '2', name: 'Coconut', quantity: '200g', expiryDate: new Date(Date.now() + 86400000 * 15).toISOString(), category: 'Staples', isCertified: true },
    { id: '3', name: 'Ghee', quantity: '100g', expiryDate: new Date(Date.now() + 86400000 * 60).toISOString(), category: 'Fats', isCertified: true },
  ]);

  const [appliances, setAppliances] = useState([
    { id: 'af', name: 'Smart Air Fryer', status: false, icon: 'fa-fire-burner' },
    { id: 'fr', name: 'Smart Fridge', status: true, icon: 'fa-snowflake' },
    { id: 'tc', name: 'TrashCan Pro', status: false, icon: 'fa-trash-can' },
  ]);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.isLoggedIn) {
          setProfile(parsed);
          setActiveScreen(AppScreen.WELCOME);
        }
      } catch (e) {
        console.error("Restore Error", e);
      }
    }
  }, []);

  useEffect(() => {
    if (profile) localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
  }, [profile]);

  const handleLoginComplete = (data: { method: 'Google' | 'Phone'; name: string; phone?: string }) => {
    setProfile({
      name: data.name,
      phone: data.phone,
      age: 25,
      weight: 70,
      dietaryPreference: 'Vegetarian',
      allergies: [],
      medicalConditions: [],
      cookingLevel: 'Beginner',
      subscription: 'Free',
      familyMembers: [],
      isLoggedIn: true,
      authMethod: data.method,
      currentCalories: 0,
      currentWater: 0,
    });
    setActiveScreen(AppScreen.ONBOARDING);
  };

  const updateConsumption = (type: 'Water' | 'Calories', amount: number) => {
    if (!profile) return;
    const newLog: ConsumptionLog = {
      id: Date.now().toString(),
      type,
      amount,
      timestamp: new Date().toISOString()
    };
    setHistory(prev => [...prev, newLog]);
    setProfile({
      ...profile,
      currentCalories: type === 'Calories' ? profile.currentCalories + amount : profile.currentCalories,
      currentWater: type === 'Water' ? Number((profile.currentWater + amount).toFixed(2)) : profile.currentWater,
    });

    if (type === 'Water' && profile.currentWater + amount >= 2.0 && profile.currentWater < 2.0) {
      showMilestone();
    }
  };

  const showMilestone = () => {
    const pun = milestonePuns[Math.floor(Math.random() * milestonePuns.length)];
    alert(`🏆 ${pun}`);
  };

  const toggleAppliance = (id: string) => {
    setAppliances(prev => prev.map(a => a.id === id ? { ...a, status: !a.status } : a));
  };

  useEffect(() => {
    if (profile && activeScreen === AppScreen.DASHBOARD) {
      const fetchSuggestions = async () => {
        try {
          const recipes = await getMealPlanSuggestions(profile, inventory);
          setSuggestions(recipes);
        } catch (error) {}
      };
      fetchSuggestions();
    }
  }, [profile, activeScreen, inventory]);

  const getTitle = () => {
    switch(activeScreen) {
      case AppScreen.DASHBOARD: return 'Dashboard';
      case AppScreen.MEAL_PLANNER: return 'Family Schedule';
      case AppScreen.INVENTORY: return 'Pantry Hub';
      case AppScreen.HEALTH_REPORT: return 'Health Stats';
      case AppScreen.APPLIANCES: return 'Kitchen Connect';
      case AppScreen.MOTIVATION_CHAT: return 'Chef Support';
      case AppScreen.SUBSCRIPTION: return 'Chef Plus';
      case AppScreen.FAMILY_MANAGEMENT: return 'Household';
      case AppScreen.PROFILE_EDIT: return 'Edit Profile';
      case AppScreen.HISTORY: return 'Logs';
      case AppScreen.PARTNER: return 'Health Partner';
      default: return 'SmartChef';
    }
  };

  if (activeScreen === AppScreen.LOGIN) return <Login onLoginComplete={handleLoginComplete} />;
  if (activeScreen === AppScreen.WELCOME) return <Welcome onContinue={() => setActiveScreen(AppScreen.DASHBOARD)} userName={profile?.name} />;

  return (
    <Layout 
      activeScreen={activeScreen} 
      setScreen={setActiveScreen} 
      title={getTitle()}
    >
      {activeScreen === AppScreen.ONBOARDING && (
        <Onboarding onComplete={(p) => { setProfile({ ...profile, ...p } as UserProfile); setActiveScreen(AppScreen.WELCOME); }} />
      )}

      {activeScreen === AppScreen.DASHBOARD && profile && (
        <>
          <Dashboard 
            profile={profile} 
            suggestions={suggestions} 
            inventory={inventory}
            onSelectRecipe={(r) => setSelectedRecipe(r)}
            setScreen={setActiveScreen}
            onUpdateConsumption={updateConsumption}
          />
          <div className="px-6 pb-6 max-w-screen-xl mx-auto">
             <button 
              onClick={() => setActiveScreen(AppScreen.MOTIVATION_CHAT)}
              className="w-full bg-emerald-100 text-emerald-700 py-4 rounded-[2rem] font-black flex items-center justify-center gap-3 border border-emerald-200 active:scale-95 transition-all shadow-sm uppercase tracking-widest text-xs"
             >
               <i className="fa-solid fa-comment-dots text-lg"></i>
               Assistant Guidance
             </button>
          </div>
        </>
      )}

      {activeScreen === AppScreen.HISTORY && (
        <History logs={history} onClose={() => setActiveScreen(AppScreen.DASHBOARD)} />
      )}

      {activeScreen === AppScreen.PARTNER && profile && (
        <Partner currentPartner={profile.healthPartner} onSelect={(p) => setProfile({...profile, healthPartner: p})} onClose={() => setActiveScreen(AppScreen.DASHBOARD)} />
      )}

      {activeScreen === AppScreen.INVENTORY && (
        <Inventory items={inventory} onAdd={() => {}} onScan={() => {}} />
      )}

      {activeScreen === AppScreen.MEAL_PLANNER && <MealPlanner />}
      {activeScreen === AppScreen.HEALTH_REPORT && <HealthReport />}
      {activeScreen === AppScreen.MOTIVATION_CHAT && <MotivationChat />}
      {activeScreen === AppScreen.SUBSCRIPTION && profile && <Subscription profile={profile} onUpdate={(tier) => setProfile({...profile, subscription: tier})} />}
      {activeScreen === AppScreen.FAMILY_MANAGEMENT && profile && (
        <FamilyManagement 
          profile={profile} 
          onAddMember={(m) => setProfile({...profile, familyMembers: [...profile.familyMembers, m]})} 
          onRemoveMember={(id) => setProfile({...profile, familyMembers: profile.familyMembers.filter(f => f.id !== id)})}
          onClose={() => setActiveScreen(AppScreen.DASHBOARD)}
        />
      )}
      {activeScreen === AppScreen.PROFILE_EDIT && profile && (
        <ProfileEdit 
          profile={profile}
          onSave={(updated) => { setProfile(updated); setActiveScreen(AppScreen.DASHBOARD); }}
          onClose={() => setActiveScreen(AppScreen.DASHBOARD)}
        />
      )}

      {activeScreen === AppScreen.APPLIANCES && (
        <div className="p-6 space-y-8 pb-24 max-w-screen-xl mx-auto animate-in fade-in duration-300">
           <div className="flex flex-col gap-4">
             <h3 className="text-3xl font-black text-gray-800 tracking-tight">Appliance Management</h3>
             <p className="text-sm text-gray-500 font-medium">Remote control your smart kitchen infrastructure.</p>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {appliances.map(app => (
               <div 
                 key={app.id} 
                 className={`p-8 rounded-[2.5rem] flex items-center justify-between border-2 transition-all duration-500 shadow-sm ${app.status ? 'bg-emerald-600 border-emerald-400 text-white shadow-emerald-100' : 'bg-white border-gray-100 text-gray-800'}`}
               >
                 <div className="flex items-center gap-6">
                    <div className={`w-16 h-16 rounded-3xl flex items-center justify-center transition-all ${app.status ? 'bg-white/20' : 'bg-gray-100 text-gray-400'}`}>
                      <i className={`fa-solid ${app.icon} text-2xl`}></i>
                    </div>
                    <div>
                      <h4 className="font-black text-xl">{app.name}</h4>
                      <p className={`text-[10px] font-black uppercase tracking-widest ${app.status ? 'text-emerald-100' : 'text-gray-400'}`}>
                        {app.status ? 'Currently Operating' : 'In Standby Mode'}
                      </p>
                    </div>
                 </div>
                 <button 
                  onClick={() => toggleAppliance(app.id)}
                  className={`w-14 h-8 rounded-full relative transition-all duration-300 ${app.status ? 'bg-white' : 'bg-gray-200'}`}
                 >
                   <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${app.status ? 'right-1 bg-emerald-600' : 'left-1 bg-white shadow-sm'}`}></div>
                 </button>
               </div>
             ))}
           </div>
        </div>
      )}

      {selectedRecipe && (
        <CookingAssistant 
          recipe={selectedRecipe} 
          onClose={() => setSelectedRecipe(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';

interface LoginProps {
  onLoginComplete: (data: { method: 'Google' | 'Phone'; name: string; phone?: string }) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginComplete }) => {
  const [phase, setPhase] = useState<'CHOICE' | 'PHONE_INPUT' | 'OTP_INPUT' | 'NAME_PROMPT'>('CHOICE');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [name, setName] = useState('');
  const [method, setMethod] = useState<'Google' | 'Phone'>('Google');

  const handleChoice = (m: 'Google' | 'Phone') => {
    setMethod(m);
    if (m === 'Phone') {
      setPhase('PHONE_INPUT');
    } else {
      setPhase('NAME_PROMPT');
    }
  };

  const handlePhoneSubmit = () => {
    if (phoneNumber.length >= 10) {
      setPhase('OTP_INPUT');
    }
  };

  const handleOtpVerify = () => {
    if (otp === '1234') { // Sample demo OTP
      setPhase('NAME_PROMPT');
    } else {
      alert("Invalid OTP. Try 1234");
    }
  };

  const handleFinalSubmit = () => {
    if (name.trim()) {
      onLoginComplete({ method, name, phone: phoneNumber });
    }
  };

  return (
    <div className="min-h-screen bg-white flex flex-col items-center justify-center p-8 space-y-12 animate-in fade-in duration-700">
      <div className="text-center space-y-4">
        <div className="w-24 h-24 bg-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-emerald-200">
          <i className="fa-solid fa-mortar-pestle text-white text-4xl"></i>
        </div>
        <h1 className="text-4xl font-black text-gray-800 tracking-tight">SmartChef</h1>
        <p className="text-gray-500 font-medium tracking-wide">Your Intelligent Kitchen Helper</p>
      </div>

      <div className="w-full max-w-sm space-y-4">
        {phase === 'CHOICE' && (
          <>
            <button 
              onClick={() => handleChoice('Google')}
              className="w-full bg-white border-2 border-gray-100 py-4 rounded-2xl flex items-center justify-center gap-4 hover:border-emerald-500 transition-all active:scale-95 group"
            >
              <i className="fa-brands fa-google text-red-500 text-lg"></i>
              <span className="font-bold text-gray-700">Continue with Google</span>
            </button>
            <button 
              onClick={() => handleChoice('Phone')}
              className="w-full bg-emerald-600 text-white py-4 rounded-2xl flex items-center justify-center gap-4 shadow-xl shadow-emerald-200 active:scale-95 transition-all"
            >
              <i className="fa-solid fa-phone text-lg"></i>
              <span className="font-bold">Login with Phone OTP</span>
            </button>
          </>
        )}

        {phase === 'PHONE_INPUT' && (
          <div className="space-y-4 animate-in slide-in-from-right duration-300">
            <input 
              type="tel" 
              placeholder="Enter Phone Number"
              value={phoneNumber}
              onChange={(e) => setPhoneNumber(e.target.value)}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handlePhoneSubmit}
              className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold active:scale-95 transition-all"
            >
              Send OTP
            </button>
          </div>
        )}

        {phase === 'OTP_INPUT' && (
          <div className="space-y-4 animate-in slide-in-from-right duration-300">
            <p className="text-center text-sm font-medium text-gray-500">Enter the verification code (1234)</p>
            <input 
              type="text" 
              placeholder="OTP"
              maxLength={4}
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-center tracking-[1rem] outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handleOtpVerify}
              className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold active:scale-95 transition-all"
            >
              Verify OTP
            </button>
          </div>
        )}

        {phase === 'NAME_PROMPT' && (
          <div className="space-y-4 animate-in slide-in-from-right duration-300">
            <p className="text-center text-sm font-medium text-gray-500">Welcome! Please enter your name to personalize your experience.</p>
            <input 
              type="text" 
              placeholder="Your Full Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handleFinalSubmit}
              className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold active:scale-95 transition-all"
            >
              Complete Login
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { UserProfile } from '../types';

interface OnboardingProps {
  initialProfile?: Partial<UserProfile>;
  onComplete: (profile: UserProfile) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ initialProfile, onComplete }) => {
  const [step, setStep] = useState(initialProfile?.name ? 1 : 1);
  const [profile, setProfile] = useState<UserProfile>({
    name: initialProfile?.name || '',
    age: initialProfile?.age || 25,
    weight: initialProfile?.weight || 70,
    dietaryPreference: initialProfile?.dietaryPreference || 'Vegetarian',
    allergies: initialProfile?.allergies || [],
    medicalConditions: initialProfile?.medicalConditions || [],
    cookingLevel: initialProfile?.cookingLevel || 'Beginner',
    subscription: initialProfile?.subscription || 'Free',
    familyMembers: initialProfile?.familyMembers || [],
    isLoggedIn: true,
    currentCalories: 0,
    currentWater: 0
  });

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const dietaryOptions = ['Vegetarian', 'Vegan', 'Non-Vegetarian', 'Keto', 'Gluten-Free'];
  const conditions = ['Diabetes', 'Hypertension', 'High Cholesterol', 'PCOS', 'None'];

  return (
    <div className="h-full bg-white max-w-md mx-auto flex flex-col p-8">
      <div className="flex justify-between items-center mb-8">
        <div className="h-2 flex-1 bg-gray-100 rounded-full mr-4">
          <div className="h-full bg-emerald-500 rounded-full transition-all" style={{ width: `${(step / 3) * 100}%` }}></div>
        </div>
        <span className="text-sm font-bold text-emerald-600">{step}/3</span>
      </div>

      <div className="flex-1 space-y-8">
        {step === 1 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Health Profile</h2>
              <p className="text-gray-500 mt-2">Let's set your basic vitals to optimize your schedule.</p>
            </div>

            <div className="space-y-4">
              {/* Only show name input if it wasn't collected during login */}
              {!initialProfile?.name && (
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">What's your name?</label>
                  <input 
                    type="text" 
                    value={profile.name}
                    onChange={(e) => setProfile({...profile, name: e.target.value})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                  />
                </div>
              )}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Age</label>
                  <input 
                    type="number" 
                    value={profile.age}
                    onChange={(e) => setProfile({...profile, age: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Weight (kg)</label>
                  <input 
                    type="number" 
                    value={profile.weight}
                    onChange={(e) => setProfile({...profile, weight: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Preferences</h2>
              <p className="text-gray-500 mt-2">Pick your primary dietary style.</p>
            </div>

            <div className="space-y-3">
              {dietaryOptions.map(opt => (
                <button
                  key={opt}
                  onClick={() => setProfile({...profile, dietaryPreference: opt})}
                  className={`w-full text-left px-4 py-3 rounded-xl border transition-all ${
                    profile.dietaryPreference === opt 
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' 
                    : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div>
              <h2 className="text-3xl font-extrabold text-gray-900">Medical Guard</h2>
              <p className="text-gray-500 mt-2">Select any existing conditions for safer menu validation.</p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              {conditions.map(c => (
                <button
                  key={c}
                  onClick={() => {
                    const exists = profile.medicalConditions.includes(c);
                    setProfile({
                      ...profile,
                      medicalConditions: exists 
                        ? profile.medicalConditions.filter(item => item !== c)
                        : [...profile.medicalConditions, c]
                    });
                  }}
                  className={`px-4 py-4 rounded-xl border text-center text-sm transition-all ${
                    profile.medicalConditions.includes(c)
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' 
                    : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-4">
        {step > 1 && (
          <button onClick={prevStep} className="flex-1 py-4 text-gray-500 font-bold">Back</button>
        )}
        <button 
          onClick={step === 3 ? () => onComplete(profile) : nextStep}
          className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-bold shadow-lg shadow-emerald-200"
        >
          {step === 3 ? 'Save Profile' : 'Continue'}
        </button>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect } from 'react';
import { UserProfile, Recipe, AppScreen, Ingredient } from '../types';

interface DashboardProps {
  profile: UserProfile;
  suggestions: Recipe[];
  inventory: Ingredient[];
  onSelectRecipe: (recipe: Recipe) => void;
  setScreen: (screen: AppScreen) => void;
  onUpdateConsumption: (type: 'Water' | 'Calories', amount: number) => void;
}

const trackingPuns = [
  "Water intake up! You're basically a cucumber with anxiety now.",
  "Calorie tracking: Because food doesn't count if you eat it standing up.",
  "Hydration level: Aquatic. Even the fish are impressed.",
  "Tracking is the only thing standing between you and a whole pizza.",
  "Drink up! Your internal maintenance crew is thirsty.",
  "Calories logged. Your metabolism thanks you for the paperwork.",
];

const healthFacts = [
  "Your heart beats about 100,000 times a day. It works harder than your internet connection.",
  "Humans are the only animals that delay sleep on purpose. Your pillow is disappointed.",
  "Walking just 2 miles a day can improve your mood more than a double espresso.",
  "Laughing is a workout. 100 laughs is equal to 10 minutes on a rowing machine.",
  "Your brain uses 20% of your body's energy. It's a high-performance computer.",
  "Standing for 3 hours a day is equivalent to running 10 marathons a year. Stand up!",
  "A balanced diet is a cookie in each hand. Just kidding, put one back.",
  "Your body is a temple, but currently, it's a temple with a really great bakery nearby."
];

const Dashboard: React.FC<DashboardProps> = ({ profile, suggestions, inventory, onSelectRecipe, setScreen, onUpdateConsumption }) => {
  const [toast, setToast] = useState<string | null>(null);
  const [dailyFact, setDailyFact] = useState("");

  useEffect(() => {
    // Pick a new fact every time dashboard mounts
    const randomFact = healthFacts[Math.floor(Math.random() * healthFacts.length)];
    setDailyFact(randomFact);
  }, []);

  const triggerTracking = (type: 'Water' | 'Calories', amount: number) => {
    onUpdateConsumption(type, amount);
    const randomPun = trackingPuns[Math.floor(Math.random() * trackingPuns.length)];
    setToast(randomPun);
    // Automatic fade out
    setTimeout(() => setToast(null), 4000);
  };

  const checkAvailability = (recipe: Recipe) => {
    return recipe.ingredients.every(req => 
      inventory.some(inv => inv.name.toLowerCase().includes(req.toLowerCase()))
    );
  };

  const getInitials = (name: string) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  return (
    <div className="space-y-8 relative max-w-screen-xl mx-auto pb-10">
      {/* Toast Feedback - Static then fades away */}
      {toast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs font-bold shadow-2xl animate-in fade-in zoom-in duration-300 text-center max-w-[90vw]">
          {toast}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <section className="flex items-center justify-between">
            <div 
              onClick={() => setScreen(AppScreen.PROFILE_EDIT)} 
              className="cursor-pointer group flex items-center gap-4"
            >
              <div className="w-14 h-14 rounded-full bg-emerald-600 text-white flex items-center justify-center shadow-lg font-black text-xl active:scale-90 transition-all group-hover:bg-emerald-700">
                {getInitials(profile.name)}
              </div>
              <div>
                <p className="text-gray-400 text-xs font-bold uppercase tracking-widest">Hello,</p>
                <h2 className="text-3xl font-black text-gray-800 tracking-tight group-hover:text-emerald-600 transition-colors">{profile.name}</h2>
              </div>
            </div>

            <div className="flex gap-2">
              <button 
                onClick={() => setScreen(AppScreen.PARTNER)}
                className="bg-blue-50 text-blue-600 px-4 py-2 rounded-xl text-[10px] font-black uppercase border border-blue-100 active:scale-95 transition-all"
              >
                {profile.healthPartner || 'Select Partner'}
              </button>
            </div>
          </section>

          {/* Daily Humorous Fact Section - Refreshes on Mount */}
          <div className="bg-amber-50 border border-amber-100 p-6 rounded-[2rem] flex gap-5 items-center shadow-sm">
             <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg">
                <i className="fa-solid fa-face-smile-wink text-xl"></i>
             </div>
             <div>
                <p className="text-[10px] font-black uppercase text-amber-800 tracking-widest mb-1">Health Insight of the Day</p>
                <p className="text-sm font-bold text-amber-900 leading-snug">{dailyFact}</p>
             </div>
          </div>

          <section 
            onClick={() => setScreen(AppScreen.HEALTH_REPORT)}
            className="bg-emerald-600 rounded-[2.5rem] p-8 md:p-12 text-white shadow-2xl shadow-emerald-200 relative overflow-hidden cursor-pointer active:scale-[0.99] transition-all group"
          >
            <div className="relative z-10">
              <div className="flex justify-between items-start mb-4">
                <p className="text-emerald-100 text-[10px] font-black uppercase tracking-widest">Daily Vital Balance</p>
                <button 
                  onClick={(e) => { e.stopPropagation(); triggerTracking('Calories', 250); }}
                  className="bg-white/20 hover:bg-white/40 p-2 rounded-xl transition-all active:scale-90"
                >
                  <i className="fa-solid fa-plus text-xs"></i> Log Meal
                </button>
              </div>
              <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                  <h3 className="text-4xl md:text-6xl font-black">{profile.currentCalories}</h3>
                  <p className="text-emerald-100 text-xs font-medium mt-1">Calories Consumed Today</p>
                </div>
                <div className="md:text-right">
                  <p className="text-2xl font-bold">{profile.dailyCalories || 2100}</p>
                  <p className="text-emerald-100 text-[10px] uppercase font-bold tracking-tighter">Daily Target</p>
                </div>
              </div>
              <div className="mt-8 space-y-2">
                <div className="w-full bg-emerald-800/40 h-3 rounded-full overflow-hidden">
                  <div className="bg-white h-full transition-all duration-1000" style={{ width: `${Math.min((profile.currentCalories / (profile.dailyCalories || 2100)) * 100, 100)}%` }}></div>
                </div>
              </div>
            </div>
            <i className="fa-solid fa-leaf absolute -right-6 -top-6 text-white/10 text-9xl md:text-[15rem] rotate-45"></i>
          </section>
