                  className="w-8 h-8 rounded-full bg-blue-50 text-blue-500 flex items-center justify-center active:scale-90 transition-all"
                >
                  <i className="fa-solid fa-plus text-xs"></i>
                </button>
              </div>
              <div>
                <p className="text-[10px] font-bold text-gray-400 uppercase">Hydration</p>
                <p className="text-lg font-black text-gray-800">{profile.currentWater} <span className="text-[10px] font-medium">Liters</span></p>
              </div>
            </div>

            <div 
              onClick={() => setScreen(AppScreen.HISTORY)}
              className="bg-gray-50 p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-3 cursor-pointer active:scale-95 transition-all group hover:bg-white"
            >
              <div className="w-10 h-10 rounded-2xl bg-emerald-50 text-emerald-600 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-colors">
                <i className="fa-solid fa-clock-rotate-left"></i>
