              <div>
                <p className="text-[10px] font-bold text-gray-400 uppercase">History & Logs</p>
                <p className="text-sm font-bold text-gray-800">Track trends</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <section className="space-y-6">
        <div className="flex items-center justify-between px-1">
          <h3 className="text-xl md:text-2xl font-black text-gray-800 uppercase tracking-tight">Approved Menu</h3>
