      <header className="px-4 md:px-8 py-4 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b border-gray-100 dark:border-gray-800 flex items-center justify-between sticky top-0 z-50">
        <div className="max-w-screen-xl mx-auto w-full flex justify-between items-center">
