            <div className="flex items-center gap-2">
              <button 
                onClick={onToggleTheme}
                className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 flex items-center justify-center text-gray-600 dark:text-gray-300 shadow-sm active:scale-90 transition-all hover:bg-gray-200 dark:hover:bg-gray-700"
                title="Toggle Theme"
              >
                <i className={`fa-solid ${theme === 'dark' ? 'fa-sun' : 'fa-moon'} text-sm md:text-base`}></i>
              </button>

              <button 
                onClick={() => setScreen(AppScreen.SUBSCRIPTION)}
                className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-emerald-50 dark:bg-emerald-900/30 border border-emerald-100 dark:border-emerald-800 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-sm active:scale-90 transition-all hover:bg-emerald-100 dark:hover:bg-emerald-800/50"
              >
                <i className="fa-solid fa-crown text-sm md:text-base"></i>
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content - Centered with max-width */}
      <main className="flex-1 w-full max-w-screen-xl mx-auto px-4 md:px-8 py-6 pb-24 md:pb-12 overflow-y-auto scroll-smooth">
        {children}
      </main>

      {/* Bottom Nav - Only visible on mobile/small tablets */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/90 dark:bg-gray-900/90 backdrop-blur-xl border-t border-gray-100 dark:border-gray-800 flex justify-around items-center py-2 safe-area-bottom shadow-[0_-10px_30px_rgba(0,0,0,0.05)] z-50 rounded-t-3xl">
        {navItems.map((item) => (
          <button
            key={item.screen}
            onClick={() => setScreen(item.screen)}
            className={`flex flex-col items-center justify-center px-4 py-2 transition-all duration-300 relative ${
              activeScreen === item.screen ? 'text-emerald-600 dark:text-emerald-400 scale-110' : 'text-gray-300 dark:text-gray-600'
            }`}
          >
            {activeScreen === item.screen && (
               <div className="absolute -top-1 w-1 h-1 bg-emerald-600 dark:bg-emerald-400 rounded-full"></div>
            )}
            <i className={`fa-solid ${item.icon} text-lg mb-1`}></i>
            <span className="text-[9px] font-bold uppercase tracking-widest">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

